414	<script>
415	/* ── State ── */
416	let activeInstance = 'paper';
417	let equityChart = null;
418	let refreshTimer = null;
419	
420	/* ── Helpers ── */
421	function api(path) {
422	  const sep = path.includes('?') ? '&' : '?';
423	  return path + sep + 'instance=' + activeInstance;
424	}
425	
426	async function fetchJSON(path) {
427	  try {
428	    const r = await fetch(api(path));
429	    if (!r.ok) throw new Error(r.status);
430	    return await r.json();
431	  } catch (e) {
432	    console.warn('Fetch failed:', path, e);
433	    return null;
434	  }
435	}
436	
437	function fmt(n, decimals) {
438	  if (n == null || isNaN(n)) return '--';
439	  decimals = decimals != null ? decimals : 2;
440	  return Number(n).toLocaleString(undefined, { minimumFractionDigits: decimals, maximumFractionDigits: decimals });
441	}
442	
443	function pnlClass(v) {
444	  if (v > 0) return 'positive';
445	  if (v < 0) return 'negative';
446	  return '';
447	}
448	
449	function dirClass(d) {
450	  if (!d) return '';
451	  const u = d.toUpperCase();
452	  if (u === 'BUY' || u === 'LONG') return 'dir-buy';
453	  if (u === 'SELL' || u === 'SHORT') return 'dir-sell';
454	  return 'dir-hold';
455	}
456	
457	function escHtml(s) {
458	  if (s == null) return '';
459	  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
460	}
461	
462	function shortTime(ts) {
463	  if (!ts) return '--';
464	  try {
465	    const d = new Date(ts);
466	    return d.toLocaleString(undefined, { month:'short', day:'numeric', hour:'2-digit', minute:'2-digit', second:'2-digit' });
467	  } catch { return ts; }
468	}
469	
470	/* ── Instance toggle ── */
471	function switchInstance(name) {
472	  activeInstance = name;
473	  document.querySelectorAll('.instance-btn').forEach(b => {
474	    b.classList.toggle('active', b.dataset.instance === name);
475	  });
476	  refreshAll();
477	}
478	
479	/* ── Start / Stop ── */
480	async function toggleInstance() {
481	  const btn = document.getElementById('startStopBtn');
482	  const isRunning = btn.classList.contains('running');
483	  const action = isRunning ? 'stop' : 'start';
484	  try {
485	    const r = await fetch('/api/instances/' + activeInstance + '/' + action, { method: 'POST' });
486	    if (!r.ok) throw new Error(r.status);
487	  } catch (e) {
488	    console.warn('Toggle failed:', e);
489	  }
490	  setTimeout(refreshInstances, 500);
491	}
492	
493	/* ── Refresh functions ── */
494	async function refreshStatus() {
495	  const d = await fetchJSON('/api/status');
496	  if (!d) return;
497	  const cur = d.currency || '';
498	  document.getElementById('cardBalance').textContent = fmt(d.balance) + ' ' + cur;
499	  document.getElementById('cardEquity').textContent = fmt(d.equity) + ' ' + cur;
500	  const pnlEl = document.getElementById('cardPnl');
501	  pnlEl.textContent = (d.unrealized_pnl >= 0 ? '+' : '') + fmt(d.unrealized_pnl) + ' ' + cur;
502	  pnlEl.className = 'card-value ' + pnlClass(d.unrealized_pnl);
503	  document.getElementById('cardPositions').textContent = d.open_positions != null ? d.open_positions : '--';
504	}
505	
506	async function refreshInstances() {
507	  const d = await fetchJSON('/api/instances');
508	  if (!d) return;
509	  const inst = d[activeInstance];
510	  if (!inst) return;
511	  const btn = document.getElementById('startStopBtn');
512	  const dot = document.getElementById('statusDot');
513	  const lbl = document.getElementById('statusLabel');
514	  const running = inst.running;
515	  const hasError = inst.last_error;
516	
517	  btn.textContent = running ? 'Stop' : 'Start';
518	  btn.className = 'ctrl-btn ' + (running ? 'running' : 'stopped');
519	  dot.className = 'status-dot ' + (running ? 'running' : 'stopped');
520	  lbl.textContent = running ? 'Running' : 'Stopped';
521	
522	  // Override with halt status from engine
523	  const eng = await fetchJSON('/api/engine-status');
524	  if (eng && eng.halted) {
525	    dot.className = 'status-dot halted';
526	    lbl.textContent = 'Halted';
527	  }
528	}
529	
530	async function refreshChart() {
531	  const data = await fetchJSON('/api/snapshots');
532	  if (!data || !data.length) return;
533	  const labels = data.map(s => {
534	    try {
535	      const d = new Date(s.timestamp);
536	      return d.toLocaleTimeString(undefined, { hour:'2-digit', minute:'2-digit' });
537	    } catch { return ''; }
538	  });
539	  const values = data.map(s => s.equity);
540	
541	  if (!equityChart) {
542	    const ctx = document.getElementById('equityChart').getContext('2d');
543	    equityChart = new Chart(ctx, {
544	      type: 'line',
545	      data: {
546	        labels: labels,
547	        datasets: [{
548	          label: 'Equity',
549	          data: values,
550	          borderColor: '#4fc3f7',
551	          backgroundColor: 'rgba(79, 195, 247, 0.08)',
552	          fill: true,
553	          tension: 0.3,
554	          pointRadius: 0,
555	          borderWidth: 2,
556	        }]
557	      },
558	      options: {
559	        responsive: true,
560	        maintainAspectRatio: false,
561	        plugins: { legend: { display: false } },
562	        scales: {
563	          x: {
564	            ticks: { color: '#8888aa', font: { size: 10 }, maxTicksLimit: 12 },
565	            grid: { color: 'rgba(255,255,255,0.04)' },
566	          },
567	          y: {
568	            ticks: { color: '#8888aa', font: { family: "'JetBrains Mono', monospace", size: 11 } },
569	            grid: { color: 'rgba(255,255,255,0.04)' },
570	          }
571	        },
572	        interaction: { intersect: false, mode: 'index' },
573	      }
574	    });
575	  } else {
576	    equityChart.data.labels = labels;
577	    equityChart.data.datasets[0].data = values;
578	    equityChart.update('none');
579	  }
580	}
581	
582	async function refreshSignals() {
583	  const wrap = document.getElementById('signalsWrap');
584	  const [signals, sentiment] = await Promise.all([
585	    fetchJSON('/api/signals'),
586	    fetchJSON('/api/sentiment'),
587	  ]);
588	  if (!signals || !signals.length) {
589	    wrap.innerHTML = '<p class="no-data">No signals available</p>';
590	    return;
591	  }
592	  const sentMap = (sentiment && sentiment.combined) ? sentiment.combined : (sentiment || {});
593	  let html = '<table><thead><tr><th>Instrument</th><th>Direction</th><th>Confidence</th><th>Sentiment</th><th>RSI 14</th><th>MACD</th><th>ADX</th></tr></thead><tbody>';
594	  signals.forEach(s => {
595	    const sent = sentMap[s.instrument] != null ? sentMap[s.instrument] : s.sentiment;
596	    const sentColor = sent > 0 ? 'color:var(--green)' : (sent < 0 ? 'color:var(--red)' : '');
597	    html += '<tr>'
598	      + '<td>' + escHtml(s.instrument) + '</td>'
599	      + '<td class="' + dirClass(s.direction) + '">' + escHtml(s.direction) + '</td>'

600	      + '<td>' + (s.confidence != null ? (s.confidence * 100).toFixed(1) + '%' : '--') + '</td>'
601	      + '<td style="' + sentColor + '">' + (sent != null ? Number(sent).toFixed(2) : '--') + '</td>'
602	      + '<td>' + (s.rsi_14 != null ? Number(s.rsi_14).toFixed(1) : '--') + '</td>'
603	      + '<td>' + (s.macd != null ? Number(s.macd).toFixed(4) : '--') + '</td>'
604	      + '<td>' + (s.adx != null ? Number(s.adx).toFixed(1) : '--') + '</td>'
605	      + '</tr>';
606	  });
607	  html += '</tbody></table>';
608	  wrap.innerHTML = html;
609	}
610	
611	async function refreshTrades() {
612	  const wrap = document.getElementById('tradesWrap');
613	  const data = await fetchJSON('/api/trades?limit=50');
614	  if (!data || !data.length) {
615	    wrap.innerHTML = '<p class="no-data">No trades recorded</p>';
616	    return;
617	  }
618	  let html = '<table><thead><tr><th>Time</th><th>Instrument</th><th>Direction</th><th>Units</th><th>Price</th><th>SL</th><th>TP</th><th>Confidence</th><th>Trade ID</th></tr></thead><tbody>';
619	  data.forEach(t => {
620	    html += '<tr>'
621	      + '<td>' + shortTime(t.timestamp) + '</td>'
622	      + '<td>' + escHtml(t.instrument) + '</td>'
623	      + '<td class="' + dirClass(t.direction) + '">' + escHtml(t.direction) + '</td>'
624	      + '<td>' + (t.units != null ? fmt(t.units, 0) : '--') + '</td>'
625	      + '<td>' + (t.price != null ? fmt(t.price, 5) : '--') + '</td>'
626	      + '<td>' + (t.stop_loss != null ? fmt(t.stop_loss, 5) : '--') + '</td>'
627	      + '<td>' + (t.take_profit != null ? fmt(t.take_profit, 5) : '--') + '</td>'
628	      + '<td>' + (t.confidence != null ? (t.confidence * 100).toFixed(1) + '%' : '--') + '</td>'
629	      + '<td style="font-size:0.72rem;color:var(--text-dim)">' + escHtml(t.trade_id || t.id || '--') + '</td>'
630	      + '</tr>';
631	  });
632	  html += '</tbody></table>';
633	  wrap.innerHTML = html;
634	}
635	
636	async function refreshBotLog() {
