async function refreshSignals() {
  const wrap = document.getElementById('signalsWrap');
  const [signals, sentiment] = await Promise.all([
    fetchJSON('/api/signals'),
    fetchJSON('/api/sentiment'),
  ]);
  if (!signals || !signals.length) {
    wrap.innerHTML = '<p class="no-data">No signals available</p>';
    _lastSignals = [];
    return;
  }
  _lastSignals = signals;
  const sentMap = (sentiment && sentiment.combined) ? sentiment.combined : (sentiment || {});

  // Separate HOLD from actionable signals
  const actionable = signals.filter(s => s.direction && s.direction.toUpperCase() !== 'HOLD');
  const holdCount = signals.length - actionable.length;

  // Sort by confidence descending
  actionable.sort((a, b) => (b.confidence || 0) - (a.confidence || 0));

  if (!actionable.length) {
    wrap.innerHTML = '<p class="no-data">No actionable signals</p>'
      + (holdCount ? '<p style="font-size:0.78rem;color:var(--text-dim);margin-top:6px">' + holdCount + ' instrument' + (holdCount !== 1 ? 's' : '') + ' on HOLD (hidden)</p>' : '');
    return;
  }

  let html = '<table><thead><tr><th>Instrument</th><th>Direction</th><th>Confidence</th><th>Sentiment</th><th>RSI 14</th><th>MACD</th><th>ADX</th></tr></thead><tbody>';
  actionable.forEach(s => {
    const sent = sentMap[s.instrument] != null ? sentMap[s.instrument] : s.sentiment;
    const sentColor = sent > 0 ? 'color:var(--green)' : (sent < 0 ? 'color:var(--red)' : '');
    html += '<tr>'
      + '<td>' + escHtml(s.instrument) + '</td>'
      + '<td class="' + dirClass(s.direction) + '">' + escHtml(s.direction) + '</td>'
      + '<td>' + (s.confidence != null ? (s.confidence * 100).toFixed(1) + '%' : '--') + '</td>'
      + '<td style="' + sentColor + '">' + (sent != null ? Number(sent).toFixed(2) : '--') + '</td>'
      + '<td>' + (s.rsi_14 != null ? Number(s.rsi_14).toFixed(1) : '--') + '</td>'
      + '<td>' + (s.macd != null ? Number(s.macd).toFixed(4) : '--') + '</td>'
      + '<td>' + (s.adx != null ? Number(s.adx).toFixed(1) : '--') + '</td>'
      + '</tr>';
  });
  html += '</tbody></table>';
  if (holdCount) {
    html += '<p style="font-size:0.78rem;color:var(--text-dim);margin-top:8px">' + holdCount + ' instrument' + (holdCount !== 1 ? 's' : '') + ' on HOLD (hidden)</p>';
  }
  wrap.innerHTML = html;
}

