/* ── Bot Summary ── */
function refreshSummary() {
  const el = document.getElementById('botSummary');
  const eng = _lastEngineStatus;
  const signals = _lastSignals || [];
  const btn = document.getElementById('startStopBtn');
  const isStopped = btn && btn.classList.contains('stopped');

  if (isStopped && !(eng && eng.halted)) {
    el.textContent = 'Bot is stopped.';
    return;
  }
  if (eng && eng.halted) {
    el.innerHTML = '<span style="color:#ff9800">\u26A0 TRADING HALTED: ' + escHtml(eng.halt_reason || 'Circuit breaker triggered') + '</span>';
    return;
  }

  const actionable = signals.filter(s => s.direction && s.direction.toUpperCase() !== 'HOLD');
  const totalInstruments = signals.length;
  const cycles = eng ? (eng.cycle_count || 0) : 0;
  const tradeCount = _lastTrade ? 'at least 1' : '0';

  if (actionable.length > 0) {
    actionable.sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
    const top = actionable[0];
    const confPct = top.confidence != null ? (top.confidence * 100).toFixed(1) + '%' : '?';
    el.textContent = 'Watching ' + actionable.length + ' potential trade' + (actionable.length !== 1 ? 's' : '')
      + '. Strongest: ' + (top.instrument || '?') + ' ' + (top.direction || '?') + ' at ' + confPct + ' confidence. '
      + cycles + ' cycle' + (cycles !== 1 ? 's' : '') + ' completed.';
  } else {
    el.textContent = 'Analyzing ' + totalInstruments + ' instrument' + (totalInstruments !== 1 ? 's' : '')
      + '. No actionable signals this cycle.';
  }
}

/* ── Alert Banner ── */
function refreshAlertBanner() {
  const banner = document.getElementById('alertBanner');
  const eng = _lastEngineStatus;

  // Check for halt
  if (eng && eng.halted) {
    showBanner('\u26A0 Trading halted: ' + (eng.halt_reason || 'Circuit breaker triggered'), 'halted');
    return;
  }

  // Check for recent trade (within 60 seconds)
  if (_lastTrade && _lastTrade.timestamp) {
    const tradeTime = new Date(_lastTrade.timestamp).getTime();
    const now = Date.now();
    const tradeId = _lastTrade.trade_id || _lastTrade.id || _lastTrade.timestamp;
    if ((now - tradeTime) < 60000 && tradeId !== _lastAlertTradeId) {
      _lastAlertTradeId = tradeId;
      const t = _lastTrade;
      const msg = '\u2713 Trade executed: ' + (t.direction || '') + ' ' + (t.instrument || '') + ' '
        + (t.units != null ? fmt(t.units, 0) + ' units' : '') + (t.price != null ? ' at ' + fmt(t.price, 5) : '');
      showBanner(msg, 'trade');
      return;
    }
  }
}

function showBanner(text, type) {
  const banner = document.getElementById('alertBanner');
  banner.textContent = text;
  banner.className = type + ' visible';
  if (_alertTimeout) clearTimeout(_alertTimeout);
  _alertTimeout = setTimeout(() => {
    banner.classList.remove('visible');
  }, 30000);
}

